#!/usr/bin/env python3
"""Shared hook runner for all hook events."""

import json
import os
import sys


def run(event: str, hook_event_name: str = "") -> None:
    """Load rules for *event*, evaluate against stdin, and print JSON result.

    Always exits 0 so that hook errors never block operations.
    """
    plugin_root = os.environ.get("CLAUDE_PLUGIN_ROOT")
    if plugin_root and plugin_root not in sys.path:
        sys.path.insert(0, plugin_root)

    try:
        from core.config_loader import load_rules
        from core.rule_engine import RuleEngine
    except ImportError as e:
        print(json.dumps({"systemMessage": f"Hookify import error: {e}"}))
        sys.exit(0)

    try:
        input_data = json.load(sys.stdin)

        # Inject hook_event_name so rule_engine can produce correct output format
        if hook_event_name:
            input_data["hook_event_name"] = hook_event_name

        # Determine effective event for rule filtering
        effective_event = event
        if event is None:
            tool_name = input_data.get("tool_name", "")
            if tool_name == "Bash":
                effective_event = "bash"
            elif tool_name in ("Edit", "Write", "MultiEdit"):
                effective_event = "file"
            else:
                effective_event = "all"

        rules = load_rules(event=effective_event)
        result = RuleEngine().evaluate_rules(rules, input_data)
        print(json.dumps(result))

    except Exception as e:
        print(json.dumps({"systemMessage": f"Hookify error: {e}"}))

    finally:
        sys.exit(0)

#!/usr/bin/env python3
"""Configuration loader for hookify plugin.

Loads rules from two directories (global → project) with project-level overrides.
- Global:  ~/.claude/hooks-rules/*.md
- Project: $CWD/.claude/hooks-rules/*.md

Same-name rules in the project directory override global rules.
Project rules with `enabled: false` can disable global rules.
"""

import os
import sys
import glob
import re
from typing import List, Optional, Dict, Any, Tuple
from dataclasses import dataclass, field


@dataclass
class Condition:
    """A single condition for matching."""

    field: str  # "command", "new_text", "file_path", "tool_name", etc.
    operator: str  # "regex_match", "contains", "equals", etc.
    pattern: str

    @classmethod
    def from_dict(cls, data: Dict[str, Any]) -> "Condition":
        return cls(
            field=data.get("field", ""),
            operator=data.get("operator", "regex_match"),
            pattern=data.get("pattern", ""),
        )


@dataclass
class Rule:
    """A hookify rule."""

    name: str
    enabled: bool
    event: str  # "bash", "file", "stop", "prompt", "all"
    pattern: Optional[str] = None
    conditions: List[Condition] = field(default_factory=list)
    action: str = "warn"  # "warn" or "block"
    tool_matcher: Optional[str] = None  # regex pattern for tool name matching
    message: str = ""
    source: str = ""  # "global" or "project"

    @classmethod
    def from_dict(cls, frontmatter: Dict[str, Any], message: str, source: str = "") -> "Rule":
        conditions = []

        if "conditions" in frontmatter:
            cond_list = frontmatter["conditions"]
            if isinstance(cond_list, list):
                conditions = [Condition.from_dict(c) for c in cond_list]

        simple_pattern = frontmatter.get("pattern")
        if simple_pattern and not conditions:
            event = frontmatter.get("event", "all")
            if event == "bash":
                cond_field = "command"
            elif event == "file":
                cond_field = "new_text"
            else:
                cond_field = "content"

            conditions = [
                Condition(field=cond_field, operator="regex_match", pattern=simple_pattern)
            ]

        return cls(
            name=frontmatter.get("name", "unnamed"),
            enabled=frontmatter.get("enabled", True),
            event=frontmatter.get("event", "all"),
            pattern=simple_pattern,
            conditions=conditions,
            action=frontmatter.get("action", "warn"),
            tool_matcher=frontmatter.get("tool_matcher"),
            message=message.strip(),
            source=source,
        )


def _unquote(value: str) -> str:
    """Strip surrounding quotes and unescape YAML double-quote escapes."""
    if len(value) >= 2 and value[0] == '"' and value[-1] == '"':
        # Double-quoted YAML: process escape sequences
        inner = value[1:-1]
        inner = inner.replace("\\\\", "\x00")  # placeholder
        inner = inner.replace("\\n", "\n")
        inner = inner.replace("\\t", "\t")
        inner = inner.replace('\\"', '"')
        inner = inner.replace("\x00", "\\")
        return inner
    if len(value) >= 2 and value[0] == "'" and value[-1] == "'":
        # Single-quoted YAML: no escape processing
        return value[1:-1]
    return value


def extract_frontmatter(content: str) -> Tuple[Dict[str, Any], str]:
    """Extract YAML frontmatter and message body from markdown.

    Simple parser — no external YAML dependency required.
    Handles nested list-of-dict items (conditions).
    """
    if not content.startswith("---"):
        return {}, content

    # Split on line-boundary "---" to avoid matching "---" inside values
    rest = content[3:]  # skip leading "---"
    if rest.startswith("\n"):
        rest = rest[1:]
    parts = rest.split("\n---\n", 1)
    if len(parts) < 2:
        # Handle file ending right after closing ---
        parts = rest.split("\n---", 1)
        if len(parts) < 2:
            return {}, content
        frontmatter_text = parts[0]
        message = ""
    else:
        frontmatter_text = parts[0]
        message = parts[1].strip()

    frontmatter: Dict[str, Any] = {}
    lines = frontmatter_text.split("\n")

    current_key: Optional[str] = None
    current_list: List[Any] = []
    current_dict: Dict[str, Any] = {}
    in_list = False
    in_dict_item = False

    def _flush_list():
        nonlocal current_key, current_list, current_dict, in_list, in_dict_item
        if in_list and current_key:
            if in_dict_item and current_dict:
                current_list.append(current_dict)
                current_dict = {}
            frontmatter[current_key] = current_list
        in_list = False
        in_dict_item = False
        current_list = []

    for line in lines:
        stripped = line.strip()
        if not stripped or stripped.startswith("#"):
            continue

        indent = len(line) - len(line.lstrip())

        # Top-level key: value
        if indent == 0 and ":" in line and not stripped.startswith("-"):
            _flush_list()

            key, value = line.split(":", 1)
            key = key.strip()
            value = value.strip()

            if not value:
                current_key = key
                in_list = True
                current_list = []
            else:
                value = _unquote(value)
                if isinstance(value, str) and value.lower() == "true":
                    value = True
                elif isinstance(value, str) and value.lower() == "false":
                    value = False
                frontmatter[key] = value

        # List item
        elif stripped.startswith("-") and in_list:
            if in_dict_item and current_dict:
                current_list.append(current_dict)
                current_dict = {}

            item_text = stripped[1:].strip()

            if ":" in item_text and "," in item_text:
                item_dict = {}
                for part in item_text.split(","):
                    if ":" in part:
                        k, v = part.split(":", 1)
                        item_dict[k.strip()] = _unquote(v.strip())
                current_list.append(item_dict)
                in_dict_item = False
            elif ":" in item_text:
                in_dict_item = True
                k, v = item_text.split(":", 1)
                current_dict = {k.strip(): _unquote(v.strip())}
            else:
                current_list.append(_unquote(item_text))
                in_dict_item = False

        # Continuation of dict item under list
        elif indent > 2 and in_dict_item and ":" in line:
            k, v = stripped.split(":", 1)
            current_dict[k.strip()] = _unquote(v.strip())

    _flush_list()

    return frontmatter, message


def load_rules(event: Optional[str] = None) -> List[Rule]:
    """Load rules from global and project directories.

    Global:  ~/.claude/hooks-rules/*.md
    Project: $CWD/.claude/hooks-rules/*.md

    Project rules override global rules with the same name.
    """
    rules_by_name: Dict[str, Rule] = {}

    # 1. Load global rules (lower priority)
    home = os.path.expanduser("~")
    global_dir = os.path.join(home, ".claude", "hooks-rules")
    _load_from_directory(global_dir, "global", rules_by_name)

    # 2. Load project rules (higher priority — overrides global)
    project_dir = os.path.join(".claude", "hooks-rules")
    _load_from_directory(project_dir, "project", rules_by_name)

    # Filter by event and enabled status
    result = []
    for rule in rules_by_name.values():
        if not rule.enabled:
            continue
        if event and rule.event != "all" and rule.event != event:
            continue
        result.append(rule)

    return result


def _load_from_directory(
    directory: str, source: str, rules_by_name: Dict[str, Rule]
) -> None:
    """Load all *.md rule files from a directory."""
    if not os.path.isdir(directory):
        return

    pattern = os.path.join(directory, "*.md")
    for file_path in sorted(glob.glob(pattern)):
        try:
            rule = _load_rule_file(file_path, source)
            if rule:
                rules_by_name[rule.name] = rule
        except Exception as e:
            print(f"Warning: Failed to load {file_path}: {e}", file=sys.stderr)


def _load_rule_file(file_path: str, source: str) -> Optional[Rule]:
    """Load a single rule file."""
    try:
        with open(file_path, "r") as f:
            content = f.read()

        frontmatter, message = extract_frontmatter(content)
        if not frontmatter:
            return None

        return Rule.from_dict(frontmatter, message, source=source)

    except Exception as e:
        print(f"Error: Cannot load {file_path}: {e}", file=sys.stderr)
        return None

#!/usr/bin/env python3
"""Rule evaluation engine for hookify plugin.

Supports regex-based tool_matcher and tool_name as a condition field.
"""

import re
import sys
from functools import lru_cache
from typing import List, Dict, Any, Optional

from core.config_loader import Rule, Condition


@lru_cache(maxsize=128)
def _compile_regex(pattern: str) -> re.Pattern:
    return re.compile(pattern, re.IGNORECASE)


class RuleEngine:
    """Evaluates rules against hook input data."""

    def evaluate_rules(
        self, rules: List[Rule], input_data: Dict[str, Any]
    ) -> Dict[str, Any]:
        """Evaluate all rules and return combined results.

        Blocking rules → deny / block.  Warning rules → systemMessage only.
        """
        hook_event = input_data.get("hook_event_name", "")
        blocking: List[Rule] = []
        warning: List[Rule] = []

        for rule in rules:
            if self._rule_matches(rule, input_data):
                if rule.action == "block":
                    blocking.append(rule)
                else:
                    warning.append(rule)

        if blocking:
            messages = [f"**[{r.name}]**\n{r.message}" for r in blocking]
            combined = "\n\n".join(messages)

            if hook_event == "Stop":
                return {
                    "decision": "block",
                    "reason": combined,
                    "systemMessage": combined,
                }
            elif hook_event in ("PreToolUse", "PostToolUse"):
                return {
                    "hookSpecificOutput": {
                        "hookEventName": hook_event,
                        "permissionDecision": "deny",
                    },
                    "systemMessage": combined,
                }
            else:
                return {"systemMessage": combined}

        if warning:
            messages = [f"**[{r.name}]**\n{r.message}" for r in warning]
            return {"systemMessage": "\n\n".join(messages)}

        return {}

    # ------------------------------------------------------------------
    # Internal helpers
    # ------------------------------------------------------------------

    def _rule_matches(self, rule: Rule, input_data: Dict[str, Any]) -> bool:
        tool_name = input_data.get("tool_name", "")
        tool_input = input_data.get("tool_input", {})

        # Check tool_matcher (regex)
        if rule.tool_matcher:
            if not self._matches_tool(rule.tool_matcher, tool_name):
                return False

        if not rule.conditions:
            # tool_matcher-only rules match when tool_matcher passes
            return bool(rule.tool_matcher)

        # All conditions must match (AND)
        return all(
            self._check_condition(c, tool_name, tool_input, input_data)
            for c in rule.conditions
        )

    def _matches_tool(self, matcher: str, tool_name: str) -> bool:
        """Regex-based tool matcher (improved from hookify's exact match)."""
        if matcher == "*":
            return True
        try:
            regex = _compile_regex(f"^(?:{matcher})$")
            return bool(regex.match(tool_name))
        except re.error:
            # Fallback to exact match on regex error
            return tool_name == matcher

    def _check_condition(
        self,
        condition: Condition,
        tool_name: str,
        tool_input: Dict[str, Any],
        input_data: Dict[str, Any],
    ) -> bool:
        field_value = self._extract_field(
            condition.field, tool_name, tool_input, input_data
        )
        if field_value is None:
            return False

        op = condition.operator
        pat = condition.pattern

        if op == "regex_match":
            return self._regex_match(pat, field_value)
        elif op == "contains":
            return pat in field_value
        elif op == "equals":
            return pat == field_value
        elif op == "not_contains":
            return pat not in field_value
        elif op == "starts_with":
            return field_value.startswith(pat)
        elif op == "ends_with":
            return field_value.endswith(pat)
        return False

    def _extract_field(
        self,
        field: str,
        tool_name: str,
        tool_input: Dict[str, Any],
        input_data: Dict[str, Any],
    ) -> Optional[str]:
        # New: tool_name as a condition field
        if field == "tool_name":
            return tool_name

        # Direct lookup in tool_input
        if field in tool_input:
            v = tool_input[field]
            return v if isinstance(v, str) else str(v)

        # Stop event fields
        if field == "reason":
            return input_data.get("reason", "")
        if field == "transcript":
            path = input_data.get("transcript_path")
            if path:
                try:
                    with open(path, "r") as f:
                        return f.read()
                except Exception:
                    return ""
            return ""
        if field == "user_prompt":
            return input_data.get("user_prompt", "")

        # Tool-specific aliases
        if tool_name == "Bash" and field == "command":
            return tool_input.get("command", "")

        if tool_name in ("Write", "Edit"):
            if field in ("content", "new_text", "new_string"):
                return tool_input.get("content") or tool_input.get("new_string", "")
            if field in ("old_text", "old_string"):
                return tool_input.get("old_string", "")
            if field == "file_path":
                return tool_input.get("file_path", "")

        if tool_name == "MultiEdit":
            if field == "file_path":
                return tool_input.get("file_path", "")
            if field in ("new_text", "content"):
                edits = tool_input.get("edits", [])
                return " ".join(e.get("new_string", "") for e in edits)

        return None

    def _regex_match(self, pattern: str, text: str) -> bool:
        try:
            return bool(_compile_regex(pattern).search(text))
        except re.error as e:
            print(f"Invalid regex '{pattern}': {e}", file=sys.stderr)
            return False

